        print(f"  - 生成洞察: {evo.get('insights_generated', 0)} 条")
        print(f"  - 累计进化: {evo.get('total_evolutions', 0)} 次")

    # 保存
    with open(PERCEPTION_DIR / "latest.json", 'w', encoding='utf-8') as f:
        json.dump(perception, f, ensure_ascii=False, indent=2)

